testbench:
`timescale 1ns/1ps
module tb;
  logic clk;
  logic rst_n;
  logic in_valid;
  logic in_ready;
  logic [7:0] in_data;
  logic out_valid;
  logic out_ready;
  logic [7:0] out_data;

  valid_ready_slice dut(
    .clk(clk),
    .rst_n(rst_n),
    .in_valid(in_valid),
    .in_ready(in_ready),
    .in_data(in_data),
    .out_valid(out_valid),
    .out_ready(out_ready),
    .out_data(out_data)
  );

  always #5 clk = ~clk;

  task step_check(input logic exp_in_ready, input logic exp_out_valid, input logic [7:0] exp_out_data);
    begin
      @(posedge clk);
      #1;
      if (in_ready !== exp_in_ready || out_valid !== exp_out_valid || out_data !== exp_out_data) begin
        $display("FAIL in_ready=%0b exp=%0b out_valid=%0b exp=%0b out_data=%0h exp=%0h", in_ready, exp_in_ready, out_valid, exp_out_valid, out_data, exp_out_data);
        $fatal(1);
      end
    end
  endtask

  initial begin
    clk = 0;
    rst_n = 0;
    in_valid = 0;
    in_data = 8'h00;
    out_ready = 0;

    step_check(1'b1, 1'b0, 8'h00);

    rst_n = 1;
    step_check(1'b1, 1'b0, 8'h00);

    in_valid = 1;
    in_data = 8'h3c;
    out_ready = 0;
    step_check(1'b0, 1'b1, 8'h3c);

    in_valid = 0;
    step_check(1'b0, 1'b1, 8'h3c);

    in_valid = 1;
    in_data = 8'ha5;
    out_ready = 1;
    step_check(1'b1, 1'b1, 8'ha5);

    in_valid = 0;
    out_ready = 1;
    step_check(1'b1, 1'b0, 8'ha5);

    in_valid = 1;
    in_data = 8'h5a;
    out_ready = 1;
    step_check(1'b1, 1'b1, 8'h5a);

    in_valid = 0;
    out_ready = 0;
    step_check(1'b0, 1'b1, 8'h5a);

    out_ready = 1;
    step_check(1'b1, 1'b0, 8'h5a);

    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module valid_ready_slice(input logic clk, input logic rst_n, input logic in_valid, output logic in_ready, input logic [7:0] in_data, output logic out_valid, input logic out_ready, output logic [7:0] out_data);
  logic full;
  logic [7:0] data_q;

  assign in_ready = !full || (out_ready && out_valid);
  assign out_valid = full;
  assign out_data = data_q;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      full <= 1'b0;
      data_q <= 8'h00;
    end else if (in_valid && in_ready) begin
      full <= 1'b1;
      data_q <= in_data;
    end else if (out_ready && out_valid) begin
      full <= 1'b0;
    end
  end
endmodule
